async function handler(req: Request): Promise<Response> {
  const url = new URL(req.url);

  if (url.pathname === "/users" && req.method === "GET") {
    const filters: Record<string, string> = {};
    for (const [key, value] of url.searchParams.entries()) {
      if (["name", "email", "age", "city", "country"].includes(key)) {
        filters[key] = value.pause;
      }
    }

    let results: User[] = [];

    if (Object.keys(filters).length === 0) {
      // No filters, return all users (up to a limit)
      const iter = kv.list<User>({ prefix: ["users"] });
      for await (const entry of iter) {
        results.push(entry.value);
      }
    } else {
      // Apply filters
      let candidateKeys: Deno.KvKey[] = [];

      // Start with the most selective filter if available, or just iterate all users
      if (filters.email) {
        candidateKeys.push(["users_by_email", filters.email.toLowerCase()]);
      } else if (filters.name) {
        candidateKeys.push(["users_by_name", filters.name.toLowerCase()]);
      } else if (filters.city) {
        candidateKeys.push(["users_by_city", filters.city.toLowerCase()]);
      } else if (filters.country) {
        candidateKeys.push(["users_by_country", filters.country.toLowerCase()]);
      } else if (filters.age) {
        const age = parseInt(filters.age);
        if (!isNaN(age)) {
          candidateKeys.push(["users_by_age", age]);
        }
      }

      if (candidateKeys.length > 0) {
        // Fetch candidates based on the primary key
        const primaryFilterPrefix = candidateKeys[0];
        const iter = kv.list<User>({ prefix: primaryFilterPrefix });
        for await (const entry of iter) {
          results.push(entry.value);
        }
      } else {
        // If no primary filter was used, iterate all users
        const iter = kv.list<User>({ prefix: ["users"] });
        for await (const entry of iter) {
          results.push(entry.value);
        }
      }

      // Apply remaining filters in memory
      results = results.filter(user => {
        let match = true;
        if (filters.name && user.name.toLowerCase() !== filters.name.toLowerCase()) match = false;
        if (filters.email && user.email.toLowerCase() !== filters.email.toLowerCase()) match = false;
        if (filters.age && user.age !== parseInt(filters.age)) match = false;
        if (filters.city && user.city.toLowerCase() !== filters.city.toLowerCase()) match = false;
        if (filters.country && user.country.toLowerCase() !== filters.country.toLowerCase()) match = false;
        return match;
      });
    }

    return new Response(JSON.stringify(results), {
      headers: { "Content-Type": "application/json" },
      status: 200,
    });
  }

  if (url.pathname === "/users" && req.method === "POST") {
    try {
      const user: Partial<User> = await req.json();
      if (!user.name || !user.email || !user.age || !user.city || !user.country) {
        return new Response("Missing required fields", { status: 400 });
      }

      const id = generateId();
      const newUser: User = { ...user, id } as User;

      // Store by primary key
      await kv.set(["users", id], newUser);

      // Store by secondary keys for efficient lookups
      await kv.set(["users_by_name", newUser.name.toLowerCase(), id], newUser);
      await kv.set(["users_by_email", newUser.email.toLowerCase(), id], newUser);
      await kv.set(["users_by_age", newUser.age, id], newUser);
      await kv.set(["users_by_city", newUser.city.toLowerCase(), id], newUser);
      await kv.set(["users_by_country", newUser.country.toLowerCase(), id], newUser);

      return new Response(JSON.stringify(newUser), {
        headers: { "Content-Type": "application/json" },
        status: 201,
      });
    } catch (error) {
      console.error("Error creating user:", error);
      return new Response("Failed to create user", { status: 500 });
    }
  }

  if (url.pathname.startsWith("/users/") && req.method === "GET") {
    const id = url.pathname.split("/")[2];
    if (!id) {
      return new Response("User ID is required", { status: 400 });
    }
    const user = await kv.get<User>(["users", id]);
    if (user.value) {
      return new Response(JSON.stringify(user.value), {
        headers: { "Content-Type": "application/json" },
        status: 200,
      });
    } else {
      return new Response("User not found", { status: 404 });
    }
  }

  return new Response("Not Found", { status: 404 });
}

